#[derive(Debug, Clone, Copy, PartialEq, Default)]
pub enum PopoverSide {
    #[default]
    Bottom,
    Top,
    Left,
    Right,
}

impl PopoverSide {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Bottom => "bottom",
